  "description": "Upload a base64-encoded, signed PDF to the document store.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "doc_id": {
        "type": "string"
      },
      "pdf_b64": {
        "type": "string"
      }
    },
    "required": [
      "doc_id",
      "pdf_b64"
    ]
  },
  "handler": "raw = base64.b64decode(pdf_b64)\nassert pdf.verify_signature(raw)\nstore.put(doc_id, raw, content_type='application/pdf')"
}

{
  "name": "return_thumbnail",
  "description": "Return a 64x64 thumbnail for the given asset as a data: URI.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "asset_id": {
        "type": "string"
      }
    },
    "required": [
      "asset_id"
    ]
  },
  "handler": "img = thumbnailer.make(asset_id, size=64)\nreturn f'data:image/webp;base64,{base64.b64encode(img).decode()}'"
}

{
  "name": "read_workspace_file",
  "description": "Read a file from the current project workspace.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "rel_path": {
        "type": "string"
      }
    },
    "required": [
      "rel_path"
    ]
  },
  "handler": "p = (WORKSPACE_ROOT / rel_path).resolve()\nassert str(p).startswith(str(WORKSPACE_ROOT))\nreturn p.read_text()"
}

{
  "name": "upload_user_avatar",
  "description": "Write the caller's uploaded avatar to their per-user folder.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "filename": {
        "type": "string",
        "pattern": "^[a-z0-9_-]+\\.(png|jpg)$"
      },
      "bytes_b64": {
        "type": "string"
      }
    },
    "required": [
      "filename",
      "bytes_b64"
    ]
  },
  "handler": "dst = AVATAR_ROOT / auth.user_id / filename\nassert str(dst.resolve()).startswith(str(AVATAR_ROOT.resolve()))\ndst.write_bytes(base64.b64decode(bytes_b64))"
}

{
  "name": "list_project_logs",
  "description": "List project log files matching a glob under the log root.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "glob": {
        "type": "string",
        "pattern": "^[A-Za-z0-9_.*?-]+$"
      }
    },
    "required": [
      "glob"
    ]
  },
  "handler": "return [str(p) for p in LOG_ROOT.glob(glob)]"
}

{
  "name": "run_ci_step",
  "description": "Run a named CI step (build/test/lint).",
  "inputSchema": {
    "type": "object",
    "properties": {
      "action": {
        "type": "string",
        "enum": [
          "build",
          "test",
          "lint"
        ]
      }
    },
    "required": [
      "action"
    ]
  },
  "handler": "CMDS = {'build': ['make', 'build'], 'test': ['pytest'], 'lint': ['ruff', 'check']}\nsubprocess.run(CMDS[action], check=True)"
}

{
  "name": "format_code",
  "description": "Format source code using the formatter registered for its language.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "language": {
        "type": "string",
        "enum": [
          "python",
          "go",
          "rust"
        ]
      },
      "source": {
        "type": "string"
      }
    },
    "required": [
      "language",
      "source"
    ]
  },
  "handler": "FMT = {'python': ['black', '-'], 'go': ['gofmt'], 'rust': ['rustfmt']}\nreturn subprocess.run(FMT[language], input=source, text=True, capture_output=True).stdout"
}

{
  "name": "container_lifecycle",
  "description": "Start, stop, or report status of a known container.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "action": {
        "type": "string",
        "enum": [
          "start",
          "stop",
          "status"
        ]
      },
      "name": {
        "type": "string",
        "pattern": "^[a-z0-9-]{1,64}$"
      }
    },
    "required": [
      "action",
      "name"
    ]
  },
  "handler": "subprocess.run(['docker', action, name], check=True)"
}

{
  "name": "load_linter",
  "description": "Activate a registered linter plugin by name.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "name": {
        "type": "string"
      }
    },
    "required": [
      "name"
    ]
  },
  "handler": "valid = {m.name for m in pkgutil.iter_modules(myapp.linters.__path__)}\nassert name in valid\nreturn importlib.import_module(f'myapp.linters.{name}').Linter()"
}

{
  "name": "activate_exporter",
  "description": "Activate an exporter declared under the 'myapp.exporters' entry point.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "name": {
        "type": "string"
      }
    },
    "required": [
      "name"
    ]
  },
  "handler": "eps = {e.name: e for e in importlib.metadata.entry_points(group='myapp.exporters')}\nreturn eps[name].load()()"
}

{
  "name": "select_renderer",
  "description": "Select a chart renderer from the registered set.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "name": {
        "type": "string",
        "enum": [
          "line",
          "bar",
          "scatter",
          "heatmap"
        ]
      }
    },
    "required": [
      "name"
    ]
  },
  "handler": "return RENDERERS[name]()"
}

{
  "name": "query_events_partition",
  "description": "Query a single event row from the month-partitioned events table.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "yyyymm": {
        "type": "string",
        "pattern": "^[0-9]{6}$"
      },
      "event_id": {
        "type": "string"
      }
    },
    "required": [
      "yyyymm",
      "event_id"
    ]
  },
  "handler": "assert re.fullmatch(r'[0-9]{6}', yyyymm)\nconn.execute(f'SELECT * FROM events_{yyyymm} WHERE id = %s', [event_id])"
}

{
  "name": "count_rows_in_table",
  "description": "Return the row count for one of the managed tables.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "table": {
        "type": "string",
        "enum": [
          "users",
          "orders",
          "events"
        ]
      }
    },
    "required": [
      "table"
    ]
  },
  "handler": "TABLES = {'users': 'users', 'orders': 'orders', 'events': 'events'}\nreturn conn.execute(f'SELECT COUNT(*) FROM {TABLES[table]}').scalar()"
}

{
  "name": "analytics_rollup",
  "description": "Aggregate a named metric over a time window.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "metric": {
        "type": "string",
        "enum": [
          "revenue",
          "signups",
          "churn"
        ]
      },
      "start": {
        "type": "string",
        "format": "date"
      },
      "end": {
        "type": "string",
        "format": "date"
      }
    },
    "required": [
      "metric",
      "start",
      "end"
    ]
  },
  "handler": "SCHEMA = 'analytics'\nconn.execute(f'SELECT SUM(v) FROM {SCHEMA}.{metric}_daily WHERE d BETWEEN %s AND %s',\n             [start, end])"
}

{
  "name": "get_aws_instance_identity",
  "description": "Return the running EC2 instance's identity document (IMDSv2).",
  "inputSchema": {
    "type": "object",
    "properties": {},
    "required": []
  },
  "handler": "t = requests.put('http://169.254.169.254/latest/api/token',\n                 headers={'X-aws-ec2-metadata-token-ttl-seconds': '60'}).text\nreturn requests.get('http://169.254.169.254/latest/dynamic/instance-identity/document',\n                    headers={'X-aws-ec2-metadata-token': t}).json()"
}

{
  "name": "k8s_service_account_token",
  "description": "Load the pod's Kubernetes service-account token for downstream API calls.",
  "inputSchema": {
    "type": "object",
    "properties": {},
    "required": []
  },
  "handler": "return Path('/var/run/secrets/kubernetes.io/serviceaccount/token').read_text()"
}

{
  "name": "gcp_metadata_project_id",
  "description": "Return the GCE project ID via the metadata server.",
  "inputSchema": {
    "type": "object",
    "properties": {},
    "required": []
  },
  "handler": "return requests.get('http://metadata.google.internal/computeMetadata/v1/project/project-id',\n                    headers={'Metadata-Flavor': 'Google'}).text"
}

{
  "name": "connect_database",
  "description": "Open a database connection using DATABASE_URL from the environment.",
  "inputSchema": {
    "type": "object",
    "properties": {},
    "required": []
  },
  "handler": "conn = psycopg.connect(os.environ['DATABASE_URL'])\nreturn {'status': 'connected', 'server_version': conn.info.server_version}"
}

{
  "name": "post_slack_message",
  "description": "Post a message to a Slack channel using the bot token.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "channel": {
        "type": "string"
      },
      "text": {
        "type": "string"
      }
    },
    "required": [
      "channel",
      "text"
    ]
  },
  "handler": "requests.post('https://slack.com/api/chat.postMessage',\n              headers={'Authorization': f\"Bearer {os.environ['SLACK_BOT_TOKEN']}\"},\n              json={'channel': channel, 'text': text})"
}

{
  "name": "s3_upload",
  "description": "Upload a blob to S3 using the ambient AWS credentials.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "bucket": {
        "type": "string"
      },
      "key": {
        "type": "string"
      },
      "body_b64": {
        "type": "string"
      }
    },
    "required": [
      "bucket",
      "key",
      "body_b64"
    ]
  },
  "handler": "boto3.client('s3').put_object(Bucket=bucket, Key=key,\n                              Body=base64.b64decode(body_b64))"
}

{
  "name": "evaluate_alert_expression",
  "description": "Evaluate a numeric alert expression against current metrics.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "expr": {
        "type": "string"
      },
      "metrics": {
        "type": "object"
      }
    },
    "required": [
      "expr",
      "metrics"
    ]
  },
  "handler": "from simpleeval import SimpleEval\nreturn SimpleEval(names=metrics).eval(expr)"
}

{
  "name": "render_report_template",
  "description": "Render a report template with the given context.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "template": {
        "type": "string"
      },
      "context": {
        "type": "object"
      }
    },
    "required": [
      "template",
      "context"
    ]
  },
  "handler": "env = jinja2.Environment(autoescape=True, undefined=jinja2.StrictUndefined)\nenv.globals = {'now': datetime.utcnow}\nreturn env.from_string(template).render(**context)"
}

{
  "name": "parse_literal_config",
  "description": "Parse a small Python-literal config blob into a dict.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "blob": {
        "type": "string"
      }
    },
    "required": [
      "blob"
    ]
  },
  "handler": "cfg = ast.literal_eval(blob)\nassert isinstance(cfg, dict)\nreturn cfg"
}

{
  "name": "canonicalize_username",
  "description": "Return the canonical (NFKC) form of a username for uniqueness checks.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "username": {
        "type": "string"
      }
    },
    "required": [
      "username"
    ]
  },
  "handler": "return unicodedata.normalize('NFKC', username).casefold()"
}

{
  "name": "normalize_filename_for_dedup",
  "description": "Return the SHA-256 of a filename after NFC normalization.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "name": {
        "type": "string"
      }
    },
    "required": [
      "name"
    ]
  },
  "handler": "n = unicodedata.normalize('NFC', name)\nreturn hashlib.sha256(n.encode()).hexdigest()"
}

{
  "name": "match_search_term_idn",
  "description": "Convert a search term to IDNA (punycode) for domain-table lookup.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "term": {
        "type": "string"
      }
    },
    "required": [
      "term"
    ]
  },
  "handler": "return term.encode('idna').decode()"
}

{
  "name": "render_markdown_with_source",
  "description": "Render a markdown doc with a provenance comment at the top.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "doc_id": {
        "type": "string"
      },
      "rev": {
        "type": "string",
        "pattern": "^[a-f0-9]{7,40}$"
      }
    },
    "required": [
      "doc_id",
      "rev"
    ]
  },
  "handler": "body = markdown.render(docs.get(doc_id))\nreturn f'<!-- source: docs/{doc_id}.md rev={rev} -->\\n{body}'"
}

{
  "name": "wrap_email_with_tracking_comment",
  "description": "Wrap an outbound email body with a debug provenance comment.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "to": {
        "type": "string"
      },
      "subject": {
        "type": "string"
      },
      "body": {
        "type": "string"
      }
    },
    "required": [
      "to",
      "subject",
      "body"
    ]
  },
  "handler": "marker = f'<!-- mailer=gbmailer build={BUILD_ID} -->' if DEBUG_EMAILS else ''\nmailer.send(to, subject, marker + body)"
}

{
  "name": "append_sourcemap_ref",
  "description": "Append the sourceMappingURL directive to a bundled JS artifact.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "bundle_path": {
        "type": "string"
      },
      "map_name": {
        "type": "string",
        "pattern": "^[A-Za-z0-9._-]+$"
      }
    },
    "required": [
      "bundle_path",
      "map_name"
    ]
  },
  "handler": "with open(bundle_path, 'a') as f:\n    f.write(f'\\n//# sourceMappingURL=https://cdn.example/maps/{map_name}\\n')"
}

{
  "name": "search_logs",
  "description": "Find log lines containing the given literal term.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "term": {
        "type": "string"
      },
      "limit": {
        "type": "integer",
        "minimum": 1,
        "maximum": 1000
      }
    },
    "required": [
      "term"
    ]
  },
  "handler": "pat = re.compile(re.escape(term))\nreturn [l for l in tail() if pat.search(l)][:limit]"
}

{
  "name": "grep_workspace",
  "description": "Run a fixed-string grep across the workspace.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "pattern": {
        "type": "string"
      }
    },
    "required": [
      "pattern"
    ]
  },
  "handler": "subprocess.run(['rg', '--fixed-strings', pattern, str(WORKSPACE_ROOT)], check=True)"
}

{
  "name": "filter_events_by_pattern",
  "description": "Filter the event stream by a restricted regex pattern.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "pattern": {
        "type": "string",
        "pattern": "^[A-Za-z0-9_.*?|-]+$"
      }
    },
    "required": [
      "pattern"
    ]
  },
  "handler": "import regex\npat = regex.compile(pattern, flags=regex.V1, timeout=0.1)\nreturn [e for e in events if pat.search(e.message)]"
}

{
  "name": "extract_dataset_bundle",
  "description": "Extract a dataset tarball into the workspace datasets directory.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "tar_path": {
        "type": "string"
      },
      "dataset_id": {
        "type": "string",
        "pattern": "^[a-z0-9-]{1,64}$"
      }
    },
    "required": [
      "tar_path",
      "dataset_id"
    ]
  },
  "handler": "dest = WORKSPACE_ROOT / 'datasets' / dataset_id\ndest.mkdir(parents=True, exist_ok=True)\nwith tarfile.open(tar_path) as tf:\n    tf.extractall(dest, filter='data')"
}

{
  "name": "install_local_plugin_package",
  "description": "Extract a local plugin zip into the plugins directory.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "zip_path": {
        "type": "string"
      }
    },
    "required": [
      "zip_path"
    ]
  },
  "handler": "dest = (PLUGINS_ROOT).resolve()\nwith zipfile.ZipFile(zip_path) as z:\n    for info in z.infolist():\n        target = (dest / info.filename).resolve()\n        if not str(target).startswith(str(dest)): continue\n        z.extract(info, dest)"
}

{
  "name": "unpack_release_artifact",
  "description": "Verify and unpack a GPG-signed release tarball.",
  "inputSchema": {
    "type": "object",
    "properties": {
      "tar_path": {
        "type": "string"
      },
      "sig_path": {
        "type": "string"
      }
    },
    "required": [
      "tar_path",
      "sig_path"
    ]
  },
  "handler": "assert gpg.verify_detached(tar_path, sig_path).valid\ndest = Path(tempfile.mkdtemp(prefix='rel-'))\nwith tarfile.open(tar_path) as tf:\n    tf.extractall(dest, filter='data')\nreturn str(dest)"
}
